261→const serverCoverage = `${coverageRoot}/server`;
262→fs.mkdirSync(testsCoverage, { recursive: true });
263→fs.mkdirSync(serverCoverage, { recursive: true });
264→
265→const consoleReporter = process.env.NODE_TEST_CONSOLE_REPORTER ?? "spec";
266→const defaultReporter = process.env.NODE_TEST_REPORTER ?? "junit";
267→const envDestination = process.env.NODE_TEST_REPORTER_DESTINATION
268→  ? resolveRepoRelative(process.env.NODE_TEST_REPORTER_DESTINATION)
269→  : null;
270→
271→const reporterArgsFor = (kind: "unit" | "integration", testName?: string) => {
272→  const destination =
273→    envDestination ??
274→    `${repoRoot}/ctrf/${kind === "unit" ? "server-unit" : "server-integration"}/${testName ? `${testName}.xml` : "all.xml"}`;
275→  ensureParentDir(destination);
276→  return {
277→    args: [
278→      `--test-reporter=${consoleReporter}`,
279→      `--test-reporter=${defaultReporter}`,
280→      "--test-reporter-destination=stdout",
