301→const waitForServer = async (url: string, timeoutMs = 30_000) => {
302→  const start = Date.now();
303→  while (Date.now() - start < timeoutMs) {
304→    try {
305→      const controller = new AbortController();
306→      const timer = setTimeout(() => controller.abort(), 2_000);
307→      const res = await fetch(url, { signal: controller.signal });
308→      clearTimeout(timer);
