  1→/**
  2→ * Server unit + integration tests on dist/esm + SEA/local server targets.
  3→ *
  4→ * Prereqs:
  5→ * - pnpm run build (packages/server-v3/dist/tests + packages/server-v3/dist/server.js).
  6→ * - SEA integration still requires build:sea when STAGEHAND_SERVER_TARGET=sea.
  7→ *
  8→ * Args: [test paths...] -- [node --test args...] | --list (prints JSON matrix)
  9→ * Env: STAGEHAND_SERVER_TARGET=sea|local|remote, STAGEHAND_BASE_URL, SEA_BINARY_NAME,
 10→ *      NODE_TEST_CONSOLE_REPORTER, NODE_TEST_REPORTER, NODE_TEST_REPORTER_DESTINATION,
 11→ *      NODE_V8_COVERAGE; writes CTRF to ctrf/node-test-*.xml by default.
 12→ * Example: STAGEHAND_SERVER_TARGET=sea pnpm run test:server -- packages/server-v3/dist/tests/integration/v3/start.test.js
 13→ */
 14→import fs from "node:fs";
 15→import path from "node:path";
 16→import { spawn, spawnSync } from "node:child_process";
 17→import { getRepoRootDir } from "./runtimePaths.js";
 18→
 19→const ensureParentDir = (filePath: string) => {
 20→  fs.mkdirSync(path.dirname(filePath), { recursive: true });
 21→};
 22→
 23→const splitArgs = (args: string[]) => {
 24→  const tokens = [...args];
 25→  while (tokens[0] === "--") {
 26→    tokens.shift();
 27→  }
 28→
 29→  const leadingExtra: string[] = [];
 30→  while (tokens.length > 0 && tokens[0].startsWith("-")) {
 31→    const arg = tokens.shift();
 32→    if (!arg) break;
 33→    if (arg === "--") break;
 34→    leadingExtra.push(arg);
 35→    if (
 36→      !arg.includes("=") &&
 37→      tokens[0] &&
 38→      tokens[0] !== "--" &&
 39→      !tokens[0].startsWith("-")
 40→    ) {
 41→      leadingExtra.push(tokens.shift() as string);
 42→    }
 43→  }
 44→
 45→  while (tokens[0] === "--") {
 46→    tokens.shift();
 47→  }
 48→
 49→  const separatorIndex = tokens.indexOf("--");
 50→  return {
 51→    paths: separatorIndex === -1 ? tokens : tokens.slice(0, separatorIndex),
 52→    extra: [
 53→      ...leadingExtra,
 54→      ...(separatorIndex === -1 ? [] : tokens.slice(separatorIndex + 1)),
 55→    ],
 56→  };
 57→};
 58→
 59→const toSafeName = (name: string) => name.replace(/[\\/]/g, "-");
 60→
 61→const collectFiles = (dir: string, suffix: string) => {
 62→  const results: string[] = [];
 63→  const walk = (current: string) => {
 64→    for (const entry of fs.readdirSync(current, { withFileTypes: true })) {
 65→      const full = `${current}/${entry.name}`;
 66→      if (entry.isDirectory()) {
 67→        walk(full);
 68→      } else if (entry.isFile() && entry.name.endsWith(suffix)) {
 69→        results.push(full);
 70→      }
 71→    }
 72→  };
 73→  if (fs.existsSync(dir)) walk(dir);
 74→  return results.sort();
 75→};
 76→
 77→const repoRoot = getRepoRootDir();
 78→
 79→const writeCtrfFromJunit = (junitPath: string, tool: string) => {
 80→  if (!fs.existsSync(junitPath)) return;
 81→  const stat = fs.statSync(junitPath);
 82→  if (stat.size === 0) return;
 83→  const ctrfPath = junitPath.match(/\.xml$/i)
 84→    ? junitPath.replace(/\.xml$/i, ".json")
 85→    : `${junitPath}.json`;
 86→  const result = spawnSync(
 87→    "pnpm",
 88→    ["exec", "junit-to-ctrf", junitPath, "-o", ctrfPath, "-t", tool],
 89→    { stdio: "inherit", cwd: repoRoot },
 90→  );
 91→  if (result.status !== 0) {
 92→    console.warn(`CTRF conversion failed for ${junitPath}.`);
 93→  }
 94→};
 95→
 96→const sourceTestsDir = `${repoRoot}/packages/server-v3/test`;
 97→const sourceUnitDir = `${sourceTestsDir}/unit`;
 98→const sourceIntegrationDir = `${sourceTestsDir}/integration`;
 99→const unitDir = `${repoRoot}/packages/server-v3/dist/tests/unit`;
100→const integrationDir = `${repoRoot}/packages/server-v3/dist/tests/integration`;
101→const allTestsDir = `${repoRoot}/packages/server-v3/dist/tests`;
102→
103→const resolveRepoRelative = (value: string) =>
104→  path.isAbsolute(value) ? value : path.resolve(repoRoot, value);
105→
106→const stripNodeReporterArgs = (argsList: string[]) => {
107→  const filtered: string[] = [];
108→  let removed = false;
109→  for (let i = 0; i < argsList.length; i++) {
110→    const arg = argsList[i];
111→    if (
112→      arg === "--test-reporter" ||
113→      arg.startsWith("--test-reporter=") ||
114→      arg === "--test-reporter-destination" ||
115→      arg.startsWith("--test-reporter-destination=")
116→    ) {
117→      removed = true;
118→      if (
119→        (arg === "--test-reporter" || arg === "--test-reporter-destination") &&
120→        argsList[i + 1]
121→      ) {
122→        i += 1;
123→      }
124→      continue;
125→    }
126→    filtered.push(arg);
127→  }
128→  return { filtered, removed };
129→};
130→
131→const toTestName = (testPath: string, root: string) => {
132→  const abs = resolveRepoRelative(testPath);
133→  const rel = path.relative(root, abs).replaceAll("\\", "/");
134→  if (!rel.startsWith("..")) {
135→    return rel.replace(/\.test\.js$/i, "");
136→  }
137→  return path.basename(abs).replace(/\.test\.js$/i, "");
138→};
139→
140→const rawArgs = process.argv.slice(2);
141→const listRequested = rawArgs.includes("--list");
142→
143→if (listRequested) {
144→  const unitTests = collectFiles(sourceUnitDir, ".test.ts").map((file) => {
145→    const relSource = path.relative(sourceTestsDir, file).replaceAll("\\", "/");
146→    const distPath = `${repoRoot}/packages/server-v3/dist/tests/${relSource.replace(/\.test\.ts$/, ".test.js")}`;
147→    const name = path.basename(file, ".test.ts");
148→    return {
149→      path: path.relative(repoRoot, distPath).replaceAll("\\", "/"),
150→      name,
151→      safe_name: toSafeName(name),
152→    };
153→  });
154→  const integrationTests = collectFiles(sourceIntegrationDir, ".test.ts").map(
155→    (file) => {
156→      const relSource = path
157→        .relative(sourceTestsDir, file)
158→        .replaceAll("\\", "/");
159→      const distPath = `${repoRoot}/packages/server-v3/dist/tests/${relSource.replace(/\.test\.ts$/, ".test.js")}`;
160→      const rel = path
161→        .relative(sourceIntegrationDir, file)
162→        .replaceAll("\\", "/")
163→        .replace(/\.test\.ts$/, "");
164→      return {
165→        path: path.relative(repoRoot, distPath).replaceAll("\\", "/"),
166→        name: rel,
167→        safe_name: toSafeName(rel),
168→      };
169→    },
