202→if (
203→  serverTarget === "local" &&
204→  !fs.existsSync(`${repoRoot}/packages/server-v3/dist/server.js`)
205→) {
206→  console.error(
207→    "Missing packages/server-v3/dist/server.js. Run pnpm run build first.",
208→  );
209→  process.exit(1);
