212→const parsedBaseUrl = new URL(baseUrl);
213→const port =
214→  parsedBaseUrl.port || (parsedBaseUrl.protocol === "https:" ? "443" : "80");
215→
216→process.env.PORT = port;
217→process.env.STAGEHAND_API_URL = baseUrl;
218→process.env.BB_ENV = process.env.BB_ENV ?? "local";
219→
220→const baseNodeOptions = "--enable-source-maps";
221→const nodeOptions = [process.env.NODE_OPTIONS, baseNodeOptions]
222→  .filter(Boolean)
223→  .join(" ");
224→
225→const allPaths =
226→  paths.length > 0
227→    ? paths.map(resolveRepoRelative)
228→    : [
229→        ...collectFiles(unitDir, ".test.js"),
230→        ...collectFiles(integrationDir, ".test.js"),
231→      ];
232→
233→const unitPaths = allPaths.filter((p) =>
234→  p.replaceAll("\\", "/").includes("/packages/server-v3/dist/tests/unit/"),
235→);
236→const integrationPaths = allPaths.filter((p) =>
237→  p
238→    .replaceAll("\\", "/")
239→    .includes("/packages/server-v3/dist/tests/integration/"),
240→);
241→
242→const singlePath = allPaths.length === 1 ? allPaths[0] : null;
243→const coverageSuffix =
244→  singlePath &&
245→  singlePath.startsWith(`${repoRoot}/packages/server-v3/dist/tests/unit/`)
246→    ? `server-unit/${path.basename(singlePath).replace(/\.test\.js$/, "")}`
247→    : singlePath &&
248→        singlePath.startsWith(
249→          `${repoRoot}/packages/server-v3/dist/tests/integration/`,
250→        )
251→      ? `server-integration/${path
252→          .relative(integrationDir, singlePath)
253→          .replace(/\.test\.js$/, "")
254→          .replaceAll("\\", "/")}`
255→      : "server";
256→
257→const coverageRoot = resolveRepoRelative(
258→  process.env.NODE_V8_COVERAGE ?? `${repoRoot}/coverage/${coverageSuffix}`,
259→);
260→const testsCoverage = `${coverageRoot}/tests`;
261→const serverCoverage = `${coverageRoot}/server`;
262→fs.mkdirSync(testsCoverage, { recursive: true });
263→fs.mkdirSync(serverCoverage, { recursive: true });
264→
265→const consoleReporter = process.env.NODE_TEST_CONSOLE_REPORTER ?? "spec";
266→const defaultReporter = process.env.NODE_TEST_REPORTER ?? "junit";
267→const envDestination = process.env.NODE_TEST_REPORTER_DESTINATION
268→  ? resolveRepoRelative(process.env.NODE_TEST_REPORTER_DESTINATION)
269→  : null;
270→
271→const reporterArgsFor = (kind: "unit" | "integration", testName?: string) => {
272→  const destination =
273→    envDestination ??
274→    `${repoRoot}/ctrf/${kind === "unit" ? "server-unit" : "server-integration"}/${testName ? `${testName}.xml` : "all.xml"}`;
275→  ensureParentDir(destination);
276→  return {
277→    args: [
278→      `--test-reporter=${consoleReporter}`,
279→      `--test-reporter=${defaultReporter}`,
280→      "--test-reporter-destination=stdout",
281→      `--test-reporter-destination=${destination}`,
282→    ],
283→    destination,
284→  };
285→};
286→
287→const runNodeTests = (files: string[], reporterArgs: string[]) =>
288→  spawnSync(
289→    process.execPath,
290→    ["--test", ...extraArgs, ...reporterArgs, ...files],
291→    {
292→      stdio: "inherit",
293→      env: {
294→        ...process.env,
295→        NODE_OPTIONS: nodeOptions,
296→        NODE_V8_COVERAGE: testsCoverage,
297→      },
298→    },
