 30→const defaultConfigPath = `${repoRoot}/packages/core/vitest.esm.config.mjs`;
 31→
 32→const resolveRepoRelative = (value: string) =>
 33→  path.isAbsolute(value) ? value : path.resolve(repoRoot, value);
 34→
 35→const hasConfigArg = (argsList: string[]) =>
 36→  argsList.some((arg, i) => {
 37→    if (arg.startsWith("--config=")) return true;
 38→    return arg === "--config" && Boolean(argsList[i + 1]);
 39→  });
 40→
 41→const toTestName = (testPath: string) => {
 42→  const abs = resolveRepoRelative(testPath);
 43→  const rel = path.relative(testsDir, abs).replaceAll("\\", "/");
 44→  if (!rel.startsWith("..")) {
 45→    return rel.replace(/\.test\.(ts|js)$/i, "");
 46→  }
 47→  return path.basename(abs).replace(/\.test\.(ts|js)$/i, "");
 48→};
 49→
 50→const listFlag = parseListFlag(process.argv.slice(2));
 51→const { paths, extra } = splitArgs(listFlag.args);
 52→
 53→if (listFlag.list) {
 54→  const tests = collectFiles(sourceTestsDir, ".test.ts");
 55→  const entries = tests.map((file) => {
 56→    const relSource = path.relative(sourceTestsDir, file).replaceAll("\\", "/");
 57→    const rel = relSource.replace(/\.test\.ts$/, "");
 58→    const distPath = `${testsDir}/${relSource.replace(/\.test\.ts$/, ".test.js")}`;
 59→    return {
