 84→const relTestName = paths.length === 1 ? toTestName(paths[0]) : null;
 85→
 86→const coverageDir = resolveRepoRelative(
 87→  process.env.NODE_V8_COVERAGE ??
 88→    (relTestName
 89→      ? `${repoRoot}/coverage/core-unit/${relTestName}`
 90→      : `${repoRoot}/coverage/core-unit`),
