 97→    return `${repoRoot}/ctrf/core-unit/all.xml`;
 98→  }
 99→  return `${repoRoot}/ctrf/core-unit/${relTestName}.xml`;
100→})();
101→const hasOutput = Boolean(findJunitPath(normalizedExtra));
102→const vitestArgs = [...normalizedExtra];
103→const consoleReporter = process.env.VITEST_CONSOLE_REPORTER ?? "default";
104→if (!hasReporterName(vitestArgs, consoleReporter)) {
105→  vitestArgs.push(`--reporter=${consoleReporter}`);
106→}
107→if (!hasReporterName(vitestArgs, "junit")) {
108→  vitestArgs.push("--reporter=junit");
109→}
110→if (!hasOutput) {
111→  ensureParentDir(defaultJunitPath);
112→  vitestArgs.push(`--outputFile.junit=${defaultJunitPath}`);
113→}
114→const junitPath = findJunitPath(vitestArgs) ?? defaultJunitPath;
115→
116→const env = {
