const splitArgs = (args: string[]) => {
  const tokens = [...args];
  while (tokens[0] === "--") {
    tokens.shift();
  }

  const leadingExtra: string[] = [];
  while (tokens.length > 0 && tokens[0].startsWith("-")) {
    const arg = tokens.shift();
    if (!arg) break;
    if (arg === "--") break;
    leadingExtra.push(arg);
    if (
      !arg.includes("=") &&
      tokens[0] &&
      tokens[0] !== "--" &&
      !tokens[0].startsWith("-")
    ) {
      leadingExtra.push(tokens.shift() as string);
    }
