292→/**
293→ * Sanitizes the V3 act result object by replacing arguments with variable names
294→ * when variables were used in the action
295→ * This prevents sensitive variable data from being stored in the database result field
296→ */
297→export function sanitizeResultWithVariables(
298→  result: ActResultV3,
299→  variables?: Record<string, string>,
300→): ActResultV3 {
301→  if (!variables || Object.keys(variables).length === 0) {
302→    return result;
303→  }
304→
305→  const sanitizedArguments = Object.keys(variables).map(
306→    (varName) => `${varName}:redacted`,
307→  );
308→
309→  return {
310→    ...result,
311→    actions: result.actions.map((action) => ({
312→      ...action,
313→      arguments: sanitizedArguments,
314→    })),
315→  };
316→}
317→
318→/**
319→ * Strips base64 media (screenshots) from agent result messages before DB storage.
320→ * Returns a shallow copy of the result with messages deeply cleaned.
321→ */
322→export function stripMediaFromAgentResult<T extends object>(result: T): T {
323→  if (!("messages" in result) || !Array.isArray(result.messages)) {
324→    return result;
325→  }
326→
327→  const cleanedMessages = result.messages.map(
328→    (msg: Record<string, unknown>) => {
329→      if (msg.role !== "tool" || !Array.isArray(msg.content)) {
330→        return msg;
331→      }
332→
333→      return {
334→        ...msg,
335→        content: msg.content.map((part: Record<string, unknown>) => {
336→          const output = part.output as
337→            | { type: string; value?: unknown }
338→            | undefined;
339→          if (
340→            !output ||
341→            output.type !== "content" ||
342→            !Array.isArray(output.value)
343→          ) {
344→            return part;
345→          }
346→
347→          const filtered = output.value.filter(
348→            (item: Record<string, unknown>) => item.type !== "media",
349→          );
350→
351→          return {
352→            ...part,
353→            output: { ...output, value: filtered },
354→          };
355→        }),
356→      };
357→    },
358→  );
359→
360→  return { ...result, messages: cleanedMessages };
361→}
362→
363→/**
364→ * Recursively removes all 'apiKey' and 'modelApiKey' properties from an object at any nesting level.
365→ * Also removes objects that become empty after sanitization.
366→ * For 'variables' objects, keeps the keys but replaces values with 'redacted'.
367→ */
368→function deepRemoveApiKeys(value: unknown): unknown {
369→  // Handle null and undefined
370→  if (value === null || value === undefined) {
371→    return value;
372→  }
373→
374→  // Handle objects
375→  if (typeof value === "object") {
376→    const result: Record<string, unknown> = {};
377→
378→    for (const [key, val] of Object.entries(value)) {
379→      // Skip apiKey and modelApiKey properties at any level
380→      if (key === "apiKey" || key === "modelApiKey") {
381→        continue;
382→      }
383→
384→      // Special handling for 'variables' - redact values but keep keys
385→      if (key === "variables" && typeof val === "object" && val !== null) {
386→        const variables = val as Record<string, unknown>;
387→        result[key] = Object.keys(variables).reduce<Record<string, string>>(
388→          (acc, varKey) => {
389→            acc[varKey] = "redacted";
390→            return acc;
391→          },
392→          {},
393→        );
394→        continue;
395→      }
396→
397→      // Recursively sanitize nested values
398→      const sanitizedValue = deepRemoveApiKeys(val);
399→
400→      // Skip empty objects (but keep null, primitives, etc.)
401→      if (
402→        sanitizedValue !== null &&
403→        sanitizedValue !== undefined &&
404→        typeof sanitizedValue === "object" &&
405→        Object.keys(sanitizedValue).length === 0
406→      ) {
407→        continue;
408→      }
409→
410→      result[key] = sanitizedValue;
411→    }
412→
413→    return result;
414→  }
415→
416→  // Return primitives as-is (string, number, boolean, etc.)
417→  return value;
418→}
