 60→export const runNavigateV3 = async ({
 61→  sessionId,
 62→  stagehand,
 63→  data,
 64→}: {
 65→  sessionId: string;
 66→  stagehand: V3Stagehand;
 67→  data: NavigateInput;
 68→}) => {
 69→  const page = data.frameId
 70→    ? stagehand.context.resolvePageByMainFrameId(data.frameId)
 71→    : await stagehand.context.awaitActivePage();
 72→
 73→  if (!page) {
 74→    throw new PageNotFoundError();
 75→  }
 76→
 77→  const action = await createAction({
 78→    sessionId,
 79→    method: "navigate",
 80→    xpath: "",
 81→    options: {
 82→      url: data.url,
 83→      ...(data.options ? { ...data.options, frameId: undefined } : {}),
 84→    },
 85→    url: data.url,
 86→  });
 87→
 88→  let result;
 89→  try {
 90→    result = await page.goto(data.url, data.options);
 91→  } catch (error) {
 92→    throw new StagehandPrimitiveError(
 93→      error instanceof Error ? error.message : String(error),
 94→      StagehandErrorCode.SDK_ERROR,
 95→      "navigate",
 96→      error instanceof Error ? error : undefined,
 97→      StatusCodes.UNPROCESSABLE_ENTITY,
 98→    );
 99→  }
