104→export const runActV3 = async ({
105→  sessionId,
106→  stagehand,
107→  data,
108→  context,
109→}: {
110→  sessionId: string;
111→  stagehand: V3Stagehand;
112→  data: ActInput;
113→  context?: StagehandToolContext;
114→}) => {
115→  const { frameId } = data;
116→  const page = frameId
117→    ? stagehand.context.resolvePageByMainFrameId(frameId)
118→    : await stagehand.context.awaitActivePage();
119→
120→  if (!page) {
121→    throw new PageNotFoundError();
122→  }
123→
124→  const url = page.url();
125→  const options = { ...data, frameId: undefined };
126→  const cacheContext = context?.cache;
127→
128→  if (cacheContext) {
129→    const { browserbaseProjectId, skipCacheHeader, logger } = cacheContext;
130→
131→    // Handle cache lookup and execution
132→    let actionId!: string; // Assigned in onCacheKeyReady
133→    let fullActResult!: ActResult; // Store full result from execution
134→    const { cacheHit } = await handleCacheAndExecute<Action[]>({
135→      method: "act",
136→      stagehand,
137→      page,
138→      data,
139→      browserbaseProjectId,
140→      sessionId,
141→      logger,
142→      skipCacheHeader,
143→      onCacheKeyReady: async (cacheKeyHash) => {
144→        // Create action with cache key
145→        const action = await createAction({
146→          sessionId,
147→          method: "act",
148→          xpath: "",
149→          options: sanitizeActionDbData(options),
150→          url,
151→          cacheKey: cacheKeyHash,
152→        });
153→        actionId = action.id;
154→        return action.id;
155→      },
156→      onCacheHit: async (cachedActions) => {
157→        // Cache hit - execute each cached action iteratively
158→        // Normalize actions to fix empty object issue from Redis cjson
159→        const normalizedActions = cachedActions.map(normalizeAction);
160→        const [firstAction, ...restActions] = normalizedActions;
161→        if (!firstAction) {
162→          throw new Error("Cached actions array is empty");
163→        }
164→        // Build options with variables for cache hit execution
165→        const cacheHitOptions = {
166→          page,
167→          variables: data.options?.variables,
168→        };
169→        let result = await stagehand.act(firstAction, cacheHitOptions);
170→        // Execute remaining actions
171→        for (const action of restActions) {
172→          result = await stagehand.act(action, cacheHitOptions);
173→        }
174→        // Store full result for later use
175→        fullActResult = result;
176→        // Return actions array to match cache value type
177→        return result.actions;
178→      },
179→      executor: async () => {
180→        const safeOptions = {
181→          model:
182→            data.options?.model &&
183→            typeof data.options.model.modelName === "string"
184→              ? {
185→                  ...resolveModelConfig(data.options.model.modelName, {
186→                    perActionApiKey: data.options.model.apiKey,
187→                    requestApiKey: context.requestModelApiKey,
188→                    gatewayEnabled: context.gatewayEnabled,
189→                    passthroughModelOptions: data.options.model,
190→                  }),
191→                }
192→              : undefined,
193→          timeout: data.options?.timeout,
194→          variables: data.options?.variables,
195→          page,
196→        };
197→
198→        try {
199→          let actResult: ActResult;
200→          if (typeof data.input === "string") {
201→            actResult = await stagehand.act(data.input, safeOptions);
202→          } else {
203→            actResult = await stagehand.act(data.input, safeOptions);
204→          }
205→
206→          // Store full result for later use
207→          fullActResult = actResult;
208→
209→          // Normalize and return actions array for caching
210→          if (Array.isArray(actResult.actions)) {
211→            return actResult.actions.map(normalizeAction);
212→          }
213→          return [];
214→        } catch (error) {
215→          throw new StagehandPrimitiveError(
216→            redactGatewayKey(
217→              error instanceof Error ? error.message : String(error),
218→            ),
219→            StagehandErrorCode.SDK_ERROR,
220→            "act",
221→            error instanceof Error ? error : undefined,
222→            StatusCodes.UNPROCESSABLE_ENTITY,
223→          );
224→        }
225→      },
226→    });
227→
228→    const sanitizedResult = sanitizeResultWithVariables(
229→      fullActResult,
230→      data.options?.variables,
231→    );
232→    await updateActionResult(actionId, sanitizedResult);
233→    return { result: fullActResult, actionId, cacheHit };
234→  }
235→
236→  const action = await createAction({
237→    sessionId,
238→    method: "act",
239→    xpath: "",
240→    options: sanitizeActionDbData(options),
241→    url,
242→  });
243→
244→  const safeOptions = {
245→    ...data.options,
246→    model:
247→      data.options?.model && typeof data.options.model.modelName === "string"
248→        ? {
249→            ...resolveModelConfig(data.options.model.modelName, {
250→              perActionApiKey: data.options.model.apiKey,
251→              requestApiKey: context?.requestModelApiKey,
252→              gatewayEnabled: context?.gatewayEnabled,
253→              passthroughModelOptions: data.options.model,
254→            }),
255→          }
256→        : undefined,
257→    page,
258→  };
259→
260→  let result: ActResult;
261→  try {
262→    if (typeof data.input === "string") {
263→      result = await stagehand.act(data.input, safeOptions);
264→    } else {
265→      result = await stagehand.act(data.input, safeOptions);
266→    }
267→  } catch (error) {
268→    throw new StagehandPrimitiveError(
269→      redactGatewayKey(error instanceof Error ? error.message : String(error)),
270→      StagehandErrorCode.SDK_ERROR,
271→      "act",
272→      error instanceof Error ? error : undefined,
273→      StatusCodes.UNPROCESSABLE_ENTITY,
274→    );
275→  }
276→
277→  const sanitizedResult = sanitizeResultWithVariables(
278→    result,
279→    data.options?.variables,
280→  );
281→  await updateActionResult(action.id, sanitizedResult);
282→  return { result, actionId: action.id };
283→};
