 10→
 11→interface JSONSchema {
 12→  type?: string | string[];
 13→  properties?: Record<string, JSONSchema>;
 14→  required?: string[];
 15→  description?: string;
 16→  items?: JSONSchema;
 17→  enum?: string[];
 18→  minimum?: number;
 19→  maximum?: number;
 20→  format?: "uri" | "url" | "email" | "uuid";
 21→  anyOf?: JSONSchema[];
 22→  oneOf?: JSONSchema[];
 23→  allOf?: JSONSchema[];
 24→  $defs?: Record<string, JSONSchema>;
 25→  $ref?: string;
 26→}
 27→
 28→/**
 29→ * Resolves all $ref pointers in a JSON Schema against its $defs, returning
 30→ * a self-contained schema with no $ref or $defs remaining.
 31→ */
 32→function resolveRefs(
 33→  schema: JSONSchema,
 34→  defs: Record<string, JSONSchema>,
 35→): JSONSchema {
 36→  if (schema.$ref) {
 37→    const refName = schema.$ref.match(/^#\/\$defs\/(.+)$/)?.[1];
 38→    const refSchema = refName ? defs[refName] : undefined;
 39→    if (refSchema) {
 40→      return resolveRefs(refSchema, defs);
 41→    }
 42→    return {};
 43→  }
 44→
 45→  const resolved: JSONSchema = { ...schema };
 46→
 47→  if (resolved.properties) {
 48→    const props: Record<string, JSONSchema> = {};
 49→    for (const [key, val] of Object.entries(resolved.properties)) {
 50→      props[key] = resolveRefs(val, defs);
 51→    }
 52→    resolved.properties = props;
 53→  }
 54→  if (resolved.items) {
 55→    resolved.items = resolveRefs(resolved.items, defs);
 56→  }
 57→  if (resolved.anyOf) {
 58→    resolved.anyOf = resolved.anyOf.map((s) => resolveRefs(s, defs));
 59→  }
 60→  if (resolved.oneOf) {
 61→    resolved.oneOf = resolved.oneOf.map((s) => resolveRefs(s, defs));
 62→  }
 63→  if (resolved.allOf) {
 64→    resolved.allOf = resolved.allOf.map((s) => resolveRefs(s, defs));
 65→  }
 66→
 67→  delete resolved.$defs;
 68→  delete resolved.$ref;
 69→  return resolved;
 70→}
 71→
 72→/**
 73→ * Converts a JSON Schema object to a Zod schema.
 74→ * @param schema The JSON Schema object to convert
 75→ * @returns A Zod schema equivalent to the input JSON Schema
 76→ */
 77→export function jsonSchemaToZod(schema: JSONSchema): ZodTypeAny {
 78→  // Resolve $ref/$defs before converting so all types are inlined
 79→  const resolved =
 80→    (schema.$defs ?? schema.$ref)
 81→      ? resolveRefs(schema, schema.$defs ?? {})
 82→      : schema;
 83→  return _jsonSchemaToZod(resolved);
 84→}
 85→
 86→function _jsonSchemaToZod(schema: JSONSchema): ZodTypeAny {
 87→  if (Array.isArray(schema.type)) {
 88→    const subSchemas = schema.type.map((singleType) => {
 89→      const sub = { ...schema, type: singleType };
 90→      return _jsonSchemaToZod(sub);
 91→    });
 92→
 93→    if (subSchemas.length === 0) {
 94→      return z.any();
 95→    } else if (subSchemas.length === 1) {
 96→      const [subSchema] = subSchemas;
 97→      if (!subSchema) {
 98→        return z.any();
 99→      }
100→      return subSchema;
101→    }
102→    return z.union(subSchemas as [ZodTypeAny, ZodTypeAny, ...ZodTypeAny[]]);
103→  }
104→
105→  if (schema.anyOf && Array.isArray(schema.anyOf)) {
106→    const subSchemas = schema.anyOf.map((sub) => _jsonSchemaToZod(sub));
107→    if (subSchemas.length === 0) {
108→      return z.any();
109→    } else if (subSchemas.length === 1) {
110→      const [subSchema] = subSchemas;
111→      if (!subSchema) {
112→        return z.any();
113→      }
114→      return subSchema;
115→    }
116→    return z.union(subSchemas as [ZodTypeAny, ZodTypeAny, ...ZodTypeAny[]]);
117→  }
118→
119→  if (schema.oneOf && Array.isArray(schema.oneOf)) {
120→    const subSchemas = schema.oneOf.map((sub) => _jsonSchemaToZod(sub));
121→    if (subSchemas.length === 0) {
122→      return z.any();
123→    } else if (subSchemas.length === 1) {
124→      const [subSchema] = subSchemas;
125→      if (!subSchema) {
126→        return z.any();
127→      }
128→      return subSchema;
129→    }
130→    return z.union(subSchemas as [ZodTypeAny, ZodTypeAny, ...ZodTypeAny[]]);
131→  }
132→
133→  switch (schema.type) {
134→    case "object":
135→      if (schema.properties) {
136→        const shape: Record<string, ZodTypeAny> = {};
137→        for (const key in schema.properties) {
138→          const subSchema = schema.properties[key];
139→          if (!subSchema) {
140→            throw new AppError(
141→              `Property ${key} is not defined in the schema`,
142→              StatusCodes.BAD_REQUEST,
143→            );
144→          }
145→          shape[key] = _jsonSchemaToZod(subSchema);
146→        }
147→        let zodObject = z.object(shape);
148→
149→        if (schema.required && Array.isArray(schema.required)) {
150→          const requiredFields = schema.required.reduce<Record<string, true>>(
151→            (acc, key) => {
152→              acc[key] = true;
153→              return acc;
154→            },
155→            {},
156→          );
157→          zodObject = zodObject.partial().required(requiredFields);
158→        }
159→
160→        if (schema.description) {
161→          zodObject = zodObject.describe(schema.description);
162→        }
163→        return zodObject;
164→      }
165→
166→      return z.object({});
167→
168→    case "array":
169→      if (schema.items) {
170→        let zodArray = z.array(_jsonSchemaToZod(schema.items));
171→        if (schema.description) {
172→          zodArray = zodArray.describe(schema.description);
173→        }
174→        return zodArray;
175→      }
176→      return z.array(z.any());
177→
178→    case "string": {
179→      if (schema.enum && schema.enum.length > 0) {
180→        return z.enum(schema.enum as [string, ...string[]]);
181→      }
182→      let zodString = z.string();
183→
184→      switch (schema.format) {
185→        case "uri":
186→        case "url":
187→          zodString = zodString.url();
188→          break;
189→        case "email":
190→          zodString = zodString.email();
191→          break;
192→        case "uuid":
193→          zodString = zodString.uuid();
194→          break;
195→        default:
196→      }
197→
198→      if (schema.description) {
199→        zodString = zodString.describe(schema.description);
200→      }
201→      return zodString;
