import { StatusCodes } from "http-status-codes";
import type { ActResult as ActResultV3 } from "stagehand-v3";
import { z } from "zod/v3";
import type { ZodTypeAny } from "zod/v3";

import type { LegacyModel, LegacyProvider } from "../types/model.js";
import { AppError } from "./errorHandler.js";

export { redactGatewayKey } from "./model-gateway.js";

interface JSONSchema {
  type?: string | string[];
  properties?: Record<string, JSONSchema>;
  required?: string[];
  description?: string;
  items?: JSONSchema;
  enum?: string[];
  minimum?: number;
  maximum?: number;
  format?: "uri" | "url" | "email" | "uuid";
  anyOf?: JSONSchema[];
  oneOf?: JSONSchema[];
  allOf?: JSONSchema[];
  $defs?: Record<string, JSONSchema>;
  $ref?: string;
}

/**
 * Resolves all $ref pointers in a JSON Schema against its $defs, returning
 * a self-contained schema with no $ref or $defs remaining.
 */
function resolveRefs(
  schema: JSONSchema,
  defs: Record<string, JSONSchema>,
): JSONSchema {
  if (schema.$ref) {
    const refName = schema.$ref.match(/^#\/\$defs\/(.+)$/)?.[1];
    const refSchema = refName ? defs[refName] : undefined;
    if (refSchema) {
      return resolveRefs(refSchema, defs);
    }
    return {};
  }

  const resolved: JSONSchema = { ...schema };

  if (resolved.properties) {
    const props: Record<string, JSONSchema> = {};
    for (const [key, val] of Object.entries(resolved.properties)) {
      props[key] = resolveRefs(val, defs);
    }
    resolved.properties = props;
  }
  if (resolved.items) {
    resolved.items = resolveRefs(resolved.items, defs);
  }
  if (resolved.anyOf) {
    resolved.anyOf = resolved.anyOf.map((s) => resolveRefs(s, defs));
  }
  if (resolved.oneOf) {
    resolved.oneOf = resolved.oneOf.map((s) => resolveRefs(s, defs));
  }
  if (resolved.allOf) {
    resolved.allOf = resolved.allOf.map((s) => resolveRefs(s, defs));
  }

  delete resolved.$defs;
  delete resolved.$ref;
  return resolved;
}

/**
 * Converts a JSON Schema object to a Zod schema.
 * @param schema The JSON Schema object to convert
 * @returns A Zod schema equivalent to the input JSON Schema
 */
export function jsonSchemaToZod(schema: JSONSchema): ZodTypeAny {
  // Resolve $ref/$defs before converting so all types are inlined
  const resolved =
    (schema.$defs ?? schema.$ref)
      ? resolveRefs(schema, schema.$defs ?? {})
      : schema;
  return _jsonSchemaToZod(resolved);
}

function _jsonSchemaToZod(schema: JSONSchema): ZodTypeAny {
  if (Array.isArray(schema.type)) {
    const subSchemas = schema.type.map((singleType) => {
      const sub = { ...schema, type: singleType };
      return _jsonSchemaToZod(sub);
    });

    if (subSchemas.length === 0) {
      return z.any();
    } else if (subSchemas.length === 1) {
      const [subSchema] = subSchemas;
      if (!subSchema) {
        return z.any();
      }
      return subSchema;
    }
    return z.union(subSchemas as [ZodTypeAny, ZodTypeAny, ...ZodTypeAny[]]);
  }

  if (schema.anyOf && Array.isArray(schema.anyOf)) {
    const subSchemas = schema.anyOf.map((sub) => _jsonSchemaToZod(sub));
    if (subSchemas.length === 0) {
      return z.any();
    } else if (subSchemas.length === 1) {
      const [subSchema] = subSchemas;
      if (!subSchema) {
        return z.any();
      }
      return subSchema;
    }
    return z.union(subSchemas as [ZodTypeAny, ZodTypeAny, ...ZodTypeAny[]]);
  }

  if (schema.oneOf && Array.isArray(schema.oneOf)) {
    const subSchemas = schema.oneOf.map((sub) => _jsonSchemaToZod(sub));
    if (subSchemas.length === 0) {
      return z.any();
    } else if (subSchemas.length === 1) {
      const [subSchema] = subSchemas;
      if (!subSchema) {
        return z.any();
      }
      return subSchema;
    }
    return z.union(subSchemas as [ZodTypeAny, ZodTypeAny, ...ZodTypeAny[]]);
  }

  switch (schema.type) {
    case "object":
      if (schema.properties) {
        const shape: Record<string, ZodTypeAny> = {};
        for (const key in schema.properties) {
          const subSchema = schema.properties[key];
          if (!subSchema) {
            throw new AppError(
              `Property ${key} is not defined in the schema`,
              StatusCodes.BAD_REQUEST,
            );
          }
          shape[key] = _jsonSchemaToZod(subSchema);
        }
        let zodObject = z.object(shape);

        if (schema.required && Array.isArray(schema.required)) {
          const requiredFields = schema.required.reduce<Record<string, true>>(
            (acc, key) => {
              acc[key] = true;
              return acc;
            },
            {},
          );
          zodObject = zodObject.partial().required(requiredFields);
        }

        if (schema.description) {
          zodObject = zodObject.describe(schema.description);
        }
        return zodObject;
      }

      return z.object({});

    case "array":
      if (schema.items) {
        let zodArray = z.array(_jsonSchemaToZod(schema.items));
        if (schema.description) {
          zodArray = zodArray.describe(schema.description);
        }
        return zodArray;
      }
      return z.array(z.any());

    case "string": {
      if (schema.enum && schema.enum.length > 0) {
        return z.enum(schema.enum as [string, ...string[]]);
      }
      let zodString = z.string();

      switch (schema.format) {
        case "uri":
        case "url":
          zodString = zodString.url();
          break;
        case "email":
          zodString = zodString.email();
          break;
        case "uuid":
          zodString = zodString.uuid();
          break;
        default:
      }

      if (schema.description) {
        zodString = zodString.describe(schema.description);
      }
      return zodString;
    }

    case "integer": // integer is a subset of number
    case "number": {
      let zodNumber = z.number();
      if (schema.minimum !== undefined) {
        zodNumber = zodNumber.min(schema.minimum);
      }
      if (schema.maximum !== undefined) {
        zodNumber = zodNumber.max(schema.maximum);
      }
      if (schema.description) {
        zodNumber = zodNumber.describe(schema.description);
      }
      return zodNumber;
    }

    case "boolean": {
      let zodBoolean = z.boolean();
      if (schema.description) {
        zodBoolean = zodBoolean.describe(schema.description);
      }
      return zodBoolean;
    }

    case "null": {
      let zodNull = z.null();
      if (schema.description) {
        zodNull = zodNull.describe(schema.description);
      }
      return zodNull;
    }

    default:
      // fallback if no recognized schema.type is present
      return z.any();
  }
}

// This function is legacy and will not be required after complete AISDK migration
export function mapModelToProvider(model: LegacyModel): LegacyProvider {
  switch (model) {
    case "gpt-4o":
    case "gpt-4o-mini":
    case "gpt-4o-2024-08-06":
    case "gpt-4o-2024-05-13":
    case "o1-mini":
    case "o1-preview":
    case "gpt-4.5-preview":
    case "o3-mini":
      return "openai";
    case "claude-3-5-sonnet-latest":
    case "claude-3-5-sonnet-20241022":
    case "claude-3-5-sonnet-20240620":
    case "claude-3-7-sonnet-20250219":
    case "claude-3-7-sonnet-latest":
      return "anthropic";
    case "gemini-1.5-flash":
    case "gemini-1.5-pro":
    case "gemini-1.5-flash-8b":
    case "gemini-2.0-flash-lite":
    case "gemini-2.0-flash":
    case "gemini-2.5-pro-preview-03-25":
    case "gemini-2.5-flash-preview-04-17":
      return "google";
    case "cerebras-llama-3.3-70b":
    case "cerebras-llama-3.1-8b":
      throw new AppError(
        "Cerebras models are not supported yet",
        StatusCodes.BAD_REQUEST,
      );
    case "groq-llama-3.3-70b-specdec":
    case "groq-llama-3.3-70b-versatile":
      throw new AppError(
        "Groq models are not supported yet",
        StatusCodes.BAD_REQUEST,
      );
    default: {
      const errorMessage = `Unknown model: ${String(model)}`;
      throw new AppError(errorMessage, StatusCodes.BAD_REQUEST);
    }
  }
}

export function sanitizeActionDbData(
  data: Record<string, unknown>,
): Record<string, unknown> {
  return deepRemoveApiKeys(data) as Record<string, unknown>;
}

/**
 * Sanitizes the V3 act result object by replacing arguments with variable names
 * when variables were used in the action
 * This prevents sensitive variable data from being stored in the database result field
 */
export function sanitizeResultWithVariables(
  result: ActResultV3,
  variables?: Record<string, string>,
): ActResultV3 {
  if (!variables || Object.keys(variables).length === 0) {
    return result;
  }

  const sanitizedArguments = Object.keys(variables).map(
    (varName) => `${varName}:redacted`,
  );

  return {
    ...result,
    actions: result.actions.map((action) => ({
      ...action,
      arguments: sanitizedArguments,
    })),
  };
}

/**
 * Strips base64 media (screenshots) from agent result messages before DB storage.
 * Returns a shallow copy of the result with messages deeply cleaned.
 */
export function stripMediaFromAgentResult<T extends object>(result: T): T {
  if (!("messages" in result) || !Array.isArray(result.messages)) {
    return result;
  }

  const cleanedMessages = result.messages.map(
    (msg: Record<string, unknown>) => {
      if (msg.role !== "tool" || !Array.isArray(msg.content)) {
        return msg;
      }

      return {
        ...msg,
        content: msg.content.map((part: Record<string, unknown>) => {
          const output = part.output as
            | { type: string; value?: unknown }
            | undefined;
          if (
            !output ||
            output.type !== "content" ||
            !Array.isArray(output.value)
          ) {
            return part;
          }

          const filtered = output.value.filter(
            (item: Record<string, unknown>) => item.type !== "media",
          );

          return {
            ...part,
            output: { ...output, value: filtered },
          };
        }),
      };
    },
  );

  return { ...result, messages: cleanedMessages };
}

/**
 * Recursively removes all 'apiKey' and 'modelApiKey' properties from an object at any nesting level.
 * Also removes objects that become empty after sanitization.
 * For 'variables' objects, keeps the keys but replaces values with 'redacted'.
 */
function deepRemoveApiKeys(value: unknown): unknown {
  // Handle null and undefined
  if (value === null || value === undefined) {
    return value;
  }

  // Handle objects
  if (typeof value === "object") {
    const result: Record<string, unknown> = {};

    for (const [key, val] of Object.entries(value)) {
      // Skip apiKey and modelApiKey properties at any level
      if (key === "apiKey" || key === "modelApiKey") {
        continue;
      }

      // Special handling for 'variables' - redact values but keep keys
      if (key === "variables" && typeof val === "object" && val !== null) {
        const variables = val as Record<string, unknown>;
        result[key] = Object.keys(variables).reduce<Record<string, string>>(
          (acc, varKey) => {
            acc[varKey] = "redacted";
            return acc;
          },
          {},
        );
        continue;
      }

      // Recursively sanitize nested values
      const sanitizedValue = deepRemoveApiKeys(val);

      // Skip empty objects (but keep null, primitives, etc.)
      if (
        sanitizedValue !== null &&
        sanitizedValue !== undefined &&
        typeof sanitizedValue === "object" &&
        Object.keys(sanitizedValue).length === 0
      ) {
        continue;
      }

      result[key] = sanitizedValue;
    }

    return result;
  }

  // Return primitives as-is (string, number, boolean, etc.)
  return value;
}

