 97→  it("enforces maximum", () => {
 98→    const zod = jsonSchemaToZod({ type: "number", maximum: 10 });
 99→    assert.equal(zod.parse(10), 10);
100→    assert.throws(() => zod.parse(11));
101→  });
102→
103→  it("enforces both minimum and maximum", () => {
104→    const zod = jsonSchemaToZod({ type: "number", minimum: 1, maximum: 10 });
105→    assert.equal(zod.parse(5), 5);
106→    assert.throws(() => zod.parse(0));
107→    assert.throws(() => zod.parse(11));
108→  });
109→});
110→
111→// ---------------------------------------------------------------------------
112→// Happy‑path: objects and arrays
113→// ---------------------------------------------------------------------------
114→describe("jsonSchemaToZod – objects and arrays", () => {
115→  it("converts a simple object", () => {
116→    const zod = jsonSchemaToZod({
117→      type: "object",
118→      properties: {
119→        name: { type: "string" },
120→        age: { type: "number" },
121→      },
122→      required: ["name", "age"],
123→    });
124→    const result = zod.parse({ name: "Alice", age: 30 });
125→    assert.deepEqual(result, { name: "Alice", age: 30 });
126→  });
127→
128→  it("converts an object with optional fields", () => {
129→    const zod = jsonSchemaToZod({
130→      type: "object",
131→      properties: {
132→        name: { type: "string" },
133→        nickname: { type: "string" },
134→      },
135→      required: ["name"],
136→    });
137→    const result = zod.parse({ name: "Alice" });
138→    assert.equal(result.name, "Alice");
139→  });
140→
141→  it("converts an empty object schema", () => {
142→    const zod = jsonSchemaToZod({ type: "object" });
143→    const result = zod.parse({});
144→    assert.deepEqual(result, {});
145→  });
146→
147→  it("converts an array of strings", () => {
148→    const zod = jsonSchemaToZod({
149→      type: "array",
150→      items: { type: "string" },
151→    });
152→    const result = zod.parse(["a", "b", "c"]);
153→    assert.deepEqual(result, ["a", "b", "c"]);
154→    assert.throws(() => zod.parse([1, 2, 3]));
155→  });
156→
157→  it("converts an array without items (z.any())", () => {
158→    const zod = jsonSchemaToZod({ type: "array" });
159→    const result = zod.parse([1, "two", true]);
160→    assert.deepEqual(result, [1, "two", true]);
161→  });
162→
163→  it("converts nested objects", () => {
164→    const zod = jsonSchemaToZod({
165→      type: "object",
166→      properties: {
167→        address: {
168→          type: "object",
169→          properties: {
170→            street: { type: "string" },
171→            city: { type: "string" },
172→          },
173→          required: ["street", "city"],
174→        },
175→      },
176→      required: ["address"],
177→    });
178→    const result = zod.parse({
179→      address: { street: "123 Main", city: "Springfield" },
180→    });
181→    assert.deepEqual(result, {
182→      address: { street: "123 Main", city: "Springfield" },
183→    });
184→  });
185→});
186→
187→// ---------------------------------------------------------------------------
188→// Happy‑path: union types (type arrays, anyOf, oneOf)
189→// ---------------------------------------------------------------------------
190→describe("jsonSchemaToZod – unions", () => {
191→  it("handles type as array (string | number)", () => {
192→    const zod = jsonSchemaToZod({ type: ["string", "number"] });
193→    assert.equal(zod.parse("hello"), "hello");
194→    assert.equal(zod.parse(42), 42);
195→    assert.throws(() => zod.parse(true));
196→  });
197→
198→  it("handles single-element type array", () => {
199→    const zod = jsonSchemaToZod({ type: ["string"] });
200→    assert.equal(zod.parse("hello"), "hello");
201→    assert.throws(() => zod.parse(42));
202→  });
203→
204→  it("handles empty type array as z.any()", () => {
205→    const zod = jsonSchemaToZod({ type: [] });
206→    assert.equal(zod.parse("anything"), "anything");
207→  });
208→
209→  it("handles anyOf", () => {
210→    const zod = jsonSchemaToZod({
211→      anyOf: [{ type: "string" }, { type: "number" }],
212→    });
213→    assert.equal(zod.parse("hello"), "hello");
214→    assert.equal(zod.parse(42), 42);
215→  });
216→
217→  it("handles oneOf", () => {
218→    const zod = jsonSchemaToZod({
219→      oneOf: [{ type: "boolean" }, { type: "null" }],
220→    });
221→    assert.equal(zod.parse(true), true);
222→    assert.equal(zod.parse(null), null);
223→  });
224→
225→  it("handles single-element anyOf", () => {
226→    const zod = jsonSchemaToZod({
227→      anyOf: [{ type: "string" }],
228→    });
229→    assert.equal(zod.parse("hello"), "hello");
230→    assert.throws(() => zod.parse(42));
231→  });
232→
233→  it("handles empty anyOf as z.any()", () => {
234→    const zod = jsonSchemaToZod({ anyOf: [] });
235→    assert.equal(zod.parse("anything"), "anything");
236→  });
237→});
238→
239→// ---------------------------------------------------------------------------
240→// Happy‑path: descriptions
241→// ---------------------------------------------------------------------------
242→describe("jsonSchemaToZod – descriptions", () => {
243→  it("preserves description on object", () => {
244→    const zod = jsonSchemaToZod({
245→      type: "object",
246→      description: "A person",
247→      properties: { name: { type: "string" } },
248→      required: ["name"],
249→    });
250→    assert.equal(zod.description, "A person");
251→  });
252→
253→  it("preserves description on string", () => {
254→    const zod = jsonSchemaToZod({
255→      type: "string",
256→      description: "A name",
257→    });
258→    assert.equal(zod.description, "A name");
259→  });
260→
261→  it("preserves description on number", () => {
262→    const zod = jsonSchemaToZod({
263→      type: "number",
264→      description: "An age",
265→    });
266→    assert.equal(zod.description, "An age");
267→  });
268→
269→  it("preserves description on boolean", () => {
270→    const zod = jsonSchemaToZod({
271→      type: "boolean",
272→      description: "Is active",
273→    });
274→    assert.equal(zod.description, "Is active");
275→  });
276→
277→  it("preserves description on array", () => {
278→    const zod = jsonSchemaToZod({
279→      type: "array",
280→      description: "A list of items",
281→      items: { type: "string" },
282→    });
283→    assert.equal(zod.description, "A list of items");
284→  });
285→});
286→
287→// ---------------------------------------------------------------------------
288→// $ref / $defs resolution (Pydantic .model_json_schema() style)
289→// ---------------------------------------------------------------------------
290→describe("jsonSchemaToZod – $ref/$defs resolution", () => {
291→  it("resolves a simple $ref", () => {
292→    const zod = jsonSchemaToZod({
293→      type: "object",
294→      properties: {
295→        address: { $ref: "#/$defs/Address" },
296→      },
297→      required: ["address"],
298→      $defs: {
299→        Address: {
300→          type: "object",
301→          properties: {
302→            street: { type: "string" },
303→            city: { type: "string" },
304→          },
305→          required: ["street", "city"],
306→        },
307→      },
308→    });
309→    const result = zod.parse({
310→      address: { street: "123 Main", city: "Springfield" },
311→    });
312→    assert.deepEqual(result, {
313→      address: { street: "123 Main", city: "Springfield" },
314→    });
315→  });
316→
317→  it("resolves nested $refs (Pydantic pattern)", () => {
318→    // Pydantic generates schemas like this for nested models
319→    const zod = jsonSchemaToZod({
320→      type: "object",
321→      properties: {
322→        company: { $ref: "#/$defs/Company" },
323→      },
324→      required: ["company"],
325→      $defs: {
326→        Company: {
327→          type: "object",
328→          properties: {
329→            name: { type: "string" },
330→            ceo: { $ref: "#/$defs/Person" },
331→          },
332→          required: ["name", "ceo"],
333→        },
334→        Person: {
335→          type: "object",
336→          properties: {
337→            first_name: { type: "string" },
338→            last_name: { type: "string" },
339→          },
340→          required: ["first_name", "last_name"],
341→        },
342→      },
343→    });
344→    const result = zod.parse({
345→      company: {
346→        name: "Acme",
347→        ceo: { first_name: "Jane", last_name: "Doe" },
348→      },
349→    });
350→    assert.deepEqual(result, {
351→      company: {
352→        name: "Acme",
353→        ceo: { first_name: "Jane", last_name: "Doe" },
354→      },
355→    });
356→  });
357→
358→  it("resolves $ref inside array items", () => {
359→    const zod = jsonSchemaToZod({
360→      type: "object",
361→      properties: {
362→        people: {
363→          type: "array",
364→          items: { $ref: "#/$defs/Person" },
365→        },
366→      },
367→      required: ["people"],
368→      $defs: {
369→        Person: {
370→          type: "object",
371→          properties: {
372→            name: { type: "string" },
373→          },
374→          required: ["name"],
375→        },
376→      },
377→    });
378→    const result = zod.parse({
379→      people: [{ name: "Alice" }, { name: "Bob" }],
380→    });
381→    assert.deepEqual(result, {
382→      people: [{ name: "Alice" }, { name: "Bob" }],
383→    });
384→  });
385→
386→  it("resolves $ref inside anyOf", () => {
387→    const zod = jsonSchemaToZod({
388→      type: "object",
389→      properties: {
390→        value: {
391→          anyOf: [{ $ref: "#/$defs/StringVal" }, { $ref: "#/$defs/NumVal" }],
392→        },
393→      },
394→      required: ["value"],
395→      $defs: {
396→        StringVal: { type: "string" },
397→        NumVal: { type: "number" },
398→      },
399→    });
400→    assert.equal(zod.parse({ value: "hello" }).value, "hello");
401→    assert.equal(zod.parse({ value: 42 }).value, 42);
402→  });
403→
404→  it("resolves $ref inside oneOf", () => {
405→    const zod = jsonSchemaToZod({
406→      type: "object",
407→      properties: {
408→        item: {
409→          oneOf: [{ $ref: "#/$defs/A" }, { $ref: "#/$defs/B" }],
410→        },
411→      },
412→      required: ["item"],
413→      $defs: {
414→        A: { type: "string" },
415→        B: { type: "boolean" },
416→      },
417→    });
418→    assert.equal(zod.parse({ item: "hello" }).item, "hello");
419→    assert.equal(zod.parse({ item: true }).item, true);
420→  });
421→
422→  it("returns empty object for unknown $ref", () => {
423→    const zod = jsonSchemaToZod({
424→      type: "object",
425→      properties: {
426→        thing: { $ref: "#/$defs/DoesNotExist" },
427→      },
428→      required: ["thing"],
429→      $defs: {},
430→    });
431→    // Unknown ref resolves to {}, which becomes z.any()
432→    const result = zod.parse({ thing: "anything" });
433→    assert.equal(result.thing, "anything");
434→  });
435→
436→  it("strips $defs from the resolved output", () => {
437→    const zod = jsonSchemaToZod({
438→      type: "object",
439→      properties: {
440→        name: { type: "string" },
441→      },
442→      required: ["name"],
443→      $defs: {
444→        Unused: { type: "number" },
445→      },
446→    });
447→    // Should still work — $defs just gets cleaned up
448→    const result = zod.parse({ name: "Alice" });
449→    assert.equal(result.name, "Alice");
450→  });
451→});
452→
453→// ---------------------------------------------------------------------------
454→// Deep recursion / self-referencing schemas
455→// ---------------------------------------------------------------------------
456→describe("jsonSchemaToZod – recursion guard", () => {
457→  it("handles direct self-reference without infinite loop", () => {
458→    // A tree node that references itself
459→    const zod = jsonSchemaToZod({
460→      type: "object",
461→      properties: {
462→        value: { type: "string" },
463→        child: { $ref: "#/$defs/Node" },
464→      },
465→      required: ["value"],
466→      $defs: {
467→        Node: {
468→          type: "object",
469→          properties: {
470→            value: { type: "string" },
471→            child: { $ref: "#/$defs/Node" },
472→          },
473→          required: ["value"],
474→        },
475→      },
476→    });
477→    // Should parse a flat node (recursive child is guarded to {})
478→    const result = zod.parse({ value: "root" });
479→    assert.equal(result.value, "root");
480→  });
481→
482→  it("handles mutual recursion (A -> B -> A)", () => {
483→    const zod = jsonSchemaToZod({
484→      type: "object",
485→      properties: {
486→        a: { $ref: "#/$defs/TypeA" },
487→      },
488→      required: ["a"],
489→      $defs: {
490→        TypeA: {
491→          type: "object",
492→          properties: {
493→            name: { type: "string" },
494→            b: { $ref: "#/$defs/TypeB" },
495→          },
496→          required: ["name"],
497→        },
498→        TypeB: {
499→          type: "object",
500→          properties: {
501→            label: { type: "string" },
502→            a: { $ref: "#/$defs/TypeA" },
503→          },
504→          required: ["label"],
505→        },
506→      },
507→    });
508→    // Should not hang — recursion is broken by the seen set
509→    const result = zod.parse({
510→      a: { name: "hello", b: { label: "world" } },
511→    });
512→    assert.equal(result.a.name, "hello");
513→    assert.equal(result.a.b.label, "world");
514→  });
515→
516→  it("handles deeply nested $ref chains (A -> B -> C -> D)", () => {
517→    const zod = jsonSchemaToZod({
518→      type: "object",
519→      properties: {
520→        start: { $ref: "#/$defs/A" },
521→      },
522→      required: ["start"],
523→      $defs: {
524→        A: {
525→          type: "object",
526→          properties: {
527→            next: { $ref: "#/$defs/B" },
528→            val: { type: "string" },
529→          },
530→          required: ["val"],
531→        },
532→        B: {
533→          type: "object",
534→          properties: {
535→            next: { $ref: "#/$defs/C" },
536→            val: { type: "number" },
537→          },
538→          required: ["val"],
539→        },
540→        C: {
541→          type: "object",
542→          properties: {
543→            next: { $ref: "#/$defs/D" },
544→            val: { type: "boolean" },
545→          },
546→          required: ["val"],
547→        },
548→        D: {
549→          type: "object",
550→          properties: {
551→            val: { type: "string" },
552→          },
553→          required: ["val"],
554→        },
555→      },
556→    });
557→    const result = zod.parse({
558→      start: {
559→        val: "a",
560→        next: {
561→          val: 1,
562→          next: {
563→            val: true,
564→            next: { val: "end" },
565→          },
566→        },
567→      },
568→    });
569→    assert.equal(result.start.val, "a");
570→    assert.equal(result.start.next.val, 1);
571→    assert.equal(result.start.next.next.val, true);
572→    assert.equal(result.start.next.next.next.val, "end");
573→  });
574→});
575→
576→// ---------------------------------------------------------------------------
577→// Edge cases / unusual schemas
578→// ---------------------------------------------------------------------------
579→describe("jsonSchemaToZod – edge cases", () => {
580→  it("handles schema with only $ref at root level", () => {
581→    const zod = jsonSchemaToZod({
582→      $ref: "#/$defs/Root",
583→      $defs: {
584→        Root: {
585→          type: "object",
586→          properties: {
587→            id: { type: "number" },
588→          },
589→          required: ["id"],
590→        },
591→      },
592→    });
593→    const result = zod.parse({ id: 42 });
594→    assert.equal(result.id, 42);
595→  });
596→
597→  it("handles allOf with multiple schemas", () => {
598→    // allOf currently resolves refs but each sub-schema becomes a union member
599→    const zod = jsonSchemaToZod({
600→      allOf: [{ type: "object", properties: { a: { type: "string" } } }],
601→    });
602→    // Single allOf element gets parsed
603→    const result = zod.parse({ a: "hello" });
604→    assert.equal(result.a, "hello");
605→  });
606→
607→  it("handles $ref inside allOf", () => {
608→    const zod = jsonSchemaToZod({
609→      type: "object",
610→      properties: {
611→        item: {
612→          allOf: [{ $ref: "#/$defs/Base" }],
613→        },
614→      },
615→      required: ["item"],
616→      $defs: {
617→        Base: {
618→          type: "object",
619→          properties: {
620→            name: { type: "string" },
621→          },
622→          required: ["name"],
623→        },
624→      },
625→    });
626→    const result = zod.parse({ item: { name: "test" } });
627→    assert.equal(result.item.name, "test");
628→  });
629→
630→  it("handles real-world Pydantic model_json_schema output", () => {
631→    // Simulates what Python's BaseModel.model_json_schema() produces
632→    const pydanticSchema = {
633→      $defs: {
634→        Address: {
635→          properties: {
636→            street: { title: "Street", type: "string" },
637→            city: { title: "City", type: "string" },
638→            zip_code: { title: "Zip Code", type: "string" },
639→          },
640→          required: ["street", "city", "zip_code"],
641→          title: "Address",
642→          type: "object",
643→        },
644→        PhoneNumber: {
645→          properties: {
646→            country_code: { title: "Country Code", type: "string" },
647→            number: { title: "Number", type: "string" },
648→          },
649→          required: ["country_code", "number"],
650→          title: "PhoneNumber",
651→          type: "object",
652→        },
653→      },
654→      properties: {
655→        name: { title: "Name", type: "string" },
656→        age: { title: "Age", type: "integer" },
657→        address: { $ref: "#/$defs/Address" },
658→        phones: {
659→          items: { $ref: "#/$defs/PhoneNumber" },
660→          title: "Phones",
661→          type: "array",
662→        },
663→      },
664→      required: ["name", "age", "address", "phones"],
665→      title: "Contact",
666→      type: "object",
667→    };
668→
669→    const zod = jsonSchemaToZod(pydanticSchema);
670→    const result = zod.parse({
671→      name: "John Doe",
672→      age: 30,
673→      address: {
674→        street: "123 Main St",
675→        city: "Anytown",
676→        zip_code: "12345",
677→      },
678→      phones: [{ country_code: "+1", number: "555-0100" }],
679→    });
680→    assert.equal(result.name, "John Doe");
681→    assert.equal(result.age, 30);
682→    assert.equal(result.address.city, "Anytown");
683→    assert.equal(result.phones[0].number, "555-0100");
684→  });
685→
686→  it("handles Pydantic Optional fields (anyOf with null)", () => {
687→    // Pydantic represents Optional[X] as anyOf: [{type: X}, {type: "null"}]
688→    const zod = jsonSchemaToZod({
689→      type: "object",
690→      properties: {
691→        name: { type: "string" },
692→        nickname: {
693→          anyOf: [{ type: "string" }, { type: "null" }],
694→        },
695→      },
696→      required: ["name"],
697→    });
698→    assert.equal(zod.parse({ name: "Alice", nickname: "Ali" }).nickname, "Ali");
699→    assert.equal(zod.parse({ name: "Alice", nickname: null }).nickname, null);
700→  });
701→
702→  it("handles schema with extra/unknown fields gracefully", () => {
703→    // Fields not in the JSONSchema interface should be ignored
704→    const schema = {
705→      type: "string",
706→      title: "A title",
707→      examples: ["foo", "bar"],
708→      default: "baz",
709→    } as Record<string, unknown>;
710→    const zod = jsonSchemaToZod(
711→      schema as Parameters<typeof jsonSchemaToZod>[0],
712→    );
713→    assert.equal(zod.parse("hello"), "hello");
714→  });
715→
716→  it("handles deeply nested objects without $ref", () => {
717→    const zod = jsonSchemaToZod({
718→      type: "object",
719→      properties: {
720→        level1: {
721→          type: "object",
722→          properties: {
723→            level2: {
724→              type: "object",
725→              properties: {
726→                level3: {
727→                  type: "object",
728→                  properties: {
729→                    value: { type: "string" },
730→                  },
731→                  required: ["value"],
732→                },
733→              },
734→              required: ["level3"],
735→            },
736→          },
737→          required: ["level2"],
738→        },
739→      },
740→      required: ["level1"],
741→    });
742→    const result = zod.parse({
743→      level1: { level2: { level3: { value: "deep" } } },
744→    });
745→    assert.equal(result.level1.level2.level3.value, "deep");
746→  });
747→
748→  it("handles array of objects with $ref items", () => {
749→    const zod = jsonSchemaToZod({
750→      type: "array",
751→      items: { $ref: "#/$defs/Item" },
752→      $defs: {
753→        Item: {
754→          type: "object",
755→          properties: {
756→            id: { type: "number" },
757→            tags: {
758→              type: "array",
759→              items: { type: "string" },
760→            },
761→          },
762→          required: ["id", "tags"],
763→        },
764→      },
765→    });
766→    const result = zod.parse([
767→      { id: 1, tags: ["a", "b"] },
768→      { id: 2, tags: ["c"] },
769→    ]);
770→    assert.equal(result.length, 2);
771→    assert.deepEqual(result[0].tags, ["a", "b"]);
772→  });
773→
774→  it("handles same $ref used in multiple places", () => {
775→    const zod = jsonSchemaToZod({
776→      type: "object",
777→      properties: {
778→        home: { $ref: "#/$defs/Address" },
779→        work: { $ref: "#/$defs/Address" },
780→      },
781→      required: ["home", "work"],
782→      $defs: {
783→        Address: {
784→          type: "object",
785→          properties: {
786→            city: { type: "string" },
787→          },
788→          required: ["city"],
789→        },
790→      },
791→    });
792→    const result = zod.parse({
793→      home: { city: "Portland" },
794→      work: { city: "Seattle" },
795→    });
796→    assert.equal(result.home.city, "Portland");
797→    assert.equal(result.work.city, "Seattle");
798→  });
799→});
